import re
from elasticsearch import Elasticsearch
from flask import Flask, request, jsonify

app = Flask(__name__)

# Initialize Elasticsearch client
es = Elasticsearch(
    ["http://localhost:9200"],
    basic_auth=("elastic", "changeme"),
)

# Allowlist of permitted aggregation script operations
ALLOWED_SCRIPT_PATTERNS = {
    "sum_field": {
        "source": "doc[params.field].value",
        "description": "Get value of a field",
    },
    "multiply_fields": {
        "source": "doc[params.field1].value * doc[params.field2].value",
        "description": "Multiply two fields",
    },
    "conditional_value": {
        "source": "doc[params.field].value > params.threshold ? 1 : 0",
        "description": "Return 1 if field exceeds threshold, else 0",
    },
    "date_diff_days": {
        "source": "(doc[params.field1].value.millis - doc[params.field2].value.millis) / 86400000",
        "description": "Difference in days between two date fields",
    },
    "percentage": {
        "source": "doc[params.numerator].value / doc[params.denominator].value * 100",
        "description": "Calculate percentage from two fields",
    },
}

# Allowed field name pattern (alphanumeric, underscores, dots)
VALID_FIELD_PATTERN = re.compile(r"^[a-zA-Z_][a-zA-Z0-9_.]*$")

# Allowed index name pattern
VALID_INDEX_PATTERN = re.compile(r"^[a-zA-Z0-9_\-]+$")


def validate_field_name(field_name):
    """Validate that a field name contains only safe characters."""
    if not isinstance(field_name, str):
        return False
    if len(field_name) > 256:
        return False
    return VALID_FIELD_PATTERN.match(field_name) is not None


def validate_index_name(index_name):
    """Validate that an index name contains only safe characters."""
    if not isinstance(index_name, str):
        return False
    if len(index_name) > 256:
        return False
    return VALID_INDEX_PATTERN.match(index_name) is not None


def validate_params(params):
    """Validate all parameter values are safe types and field names are valid."""
    if not isinstance(params, dict):
        return False, "Params must be a dictionary"

    for key, value in params.items():
        if not validate_field_name(key):
            return False, f"Invalid parameter name: {key}"

        if isinstance(value, str):
            if not validate_field_name(value):
                return False, f"Invalid field name in parameter '{key}': {value}"
        elif isinstance(value, (int, float)):
            # Numeric parameters are allowed (e.g., thresholds)
            continue
        else:
            return False, f"Invalid parameter type for '{key}': only strings and numbers allowed"

    return True, None


@app.route("/api/scripted_aggregation", methods=["POST"])
def scripted_aggregation():
    """
    Execute a predefined scripted aggregation against Elasticsearch.

    Instead of accepting arbitrary script code (which would be a code injection risk),
    this endpoint accepts a script_id that maps to a predefined, safe script template,
    along with parameters to customize the script behavior.

    Expected JSON body:
    {
        "index": "my_index",
        "script_id": "sum_field",
        "params": {"field": "price"},
        "agg_type": "sum",
        "query": {"match_all": {}}  // optional
    }
    """
    if not request.is_json:
        return jsonify({"error": "Request must be JSON"}), 400

    data = request.get_json()

    # Validate required fields
    index = data.get("index")
    script_id = data.get("script_id")
    params = data.get("params", {})
    agg_type = data.get("agg_type", "sum")
    query = data.get("query", {"match_all": {}})

    if not index:
        return jsonify({"error": "Missing 'index' field"}), 400

    if not validate_index_name(index):
        return jsonify({"error": "Invalid index name"}), 400

    if not script_id:
        return jsonify({"error": "Missing 'script_id' field"}), 400

    # Only allow predefined scripts - never accept arbitrary script code
    if script_id not in ALLOWED_SCRIPT_PATTERNS:
        available = list(ALLOWED_SCRIPT_PATTERNS.keys())
        return jsonify({
            "error": f"Unknown script_id: '{script_id}'",
            "available_scripts": available,
            "descriptions": {k: v["description"] for k, v in ALLOWED_SCRIPT_PATTERNS.items()},
        }), 400

    # Validate parameters
    is_valid, error_msg = validate_params(params)
    if not is_valid:
        return jsonify({"error": error_msg}), 400

    # Validate aggregation type
    allowed_agg_types = {"sum", "avg", "min", "max", "value_count", "stats"}
    if agg_type not in allowed_agg_types:
        return jsonify({
            "error": f"Invalid agg_type: '{agg_type}'",
            "allowed": list(allowed_agg_types),
        }), 400

    # Validate query structure (basic validation)
    if not isinstance(query, dict):
        return jsonify({"error": "Query must be a dictionary"}), 400

    # Build the aggregation using the predefined script
    script_template = ALLOWED_SCRIPT_PATTERNS[script_id]

    agg_body = {
        "size": 0,
        "query": query,
        "aggs": {
            "scripted_result": {
                agg_type: {
                    "script": {
                        "lang": "painless",
                        "source": script_template["source"],
                        "params": params,
                    }
                }
            }
        },
    }

    try:
        result = es.search(index=index, body=agg_body)
        aggregation_result = result.get("aggregations", {}).get("scripted_result", {})

        return jsonify({
            "success": True,
            "script_used": script_id,
            "script_description": script_template["description"],
            "result": aggregation_result,
            "total_hits": result.get("hits", {}).get("total", {}).get("value", 0),
        })

    except Exception as e:
        # Don't leak internal details in error messages
        app.logger.error(f"Elasticsearch query failed: {e}")
        return jsonify({
            "error": "Aggregation query failed. Please check your parameters and try again.",
        }), 500


@app.route("/api/available_scripts", methods=["GET"])
def available_scripts():
    """List all available predefined scripts and their descriptions."""
    scripts = {}
    for script_id, script_info in ALLOWED_SCRIPT_PATTERNS.items():
        scripts[script_id] = {
            "description": script_info["description"],
            "source": script_info["source"],
        }

    return jsonify({
        "available_scripts": scripts,
        "allowed_agg_types": ["sum", "avg", "min", "max", "value_count", "stats"],
    })


@app.route("/api/health", methods=["GET"])
def health():
    """Check Elasticsearch cluster health."""
    try:
        health_info = es.cluster.health()
        return jsonify({
            "elasticsearch": {
                "status": health_info.get("status"),
                "cluster_name": health_info.get("cluster_name"),
                "number_of_nodes": health_info.get("number_of_nodes"),
            }
        })
    except Exception as e:
        app.logger.error(f"Health check failed: {e}")
        return jsonify({"error": "Elasticsearch is not available"}), 503


if __name__ == "__main__":
    # In production, use a proper WSGI server like gunicorn
    # and set debug=False
    app.run(host="127.0.0.1", port=5000, debug=False)